@spec tm_pc_synthesis_spec  src=tests/specs/tm_pc_synthesis_spec.lua  loc=375  sha=abecbf0  cases=15
@exercises midiManager (h.mm), trackerManager (h.tm)
@surface   mm:notes, tm:getChannel, fm:dump, tm:addEvent, tm:flush, tm:assignEvent, tm:deleteEvent
@harness   mk{seed.notes, seed.ccs}

# Intent
  Pins commit 2b: tm synthesises PCs from per-note `sample` under
  trackerMode. Realised-time grouping; leftmost lane wins; losers
  carry `sampleShadowed=true` for renderer dimming. Mutation hooks
  keep the synthesised stream in lockstep with note edits.

# Helpers
  @fn pcsOnChan(dump, chan)  @ 8-17
  @fn uuidOfNote(mm, chan, pitch)  @ 21-25
      -- Locate a note by (chan, pitch) and return its mm handle. mm:notes still
      -- yields (loc, evt); we ignore the loc and take the event's uuid.
  @fn laneEvent(tm, chan, lane, i)  @ 27-29

# Cases
  @case 'three lane-1 notes synthesise three PCs at their realised onsets'  [harness]  @ 36-50
  @case 'PC lands at realised ppq, not intent (delay shifts the PC too)'  [harness]  @ 54-68
  @case 'changing sample on a note resyncs its PC val'  [harness]  @ 74-90
  @case 'deleting the only note at a realised ppq drops its PC'  [harness]  @ 94-109
  @case 'cross-channel: editing one chan does not clobber another chan\'s PC'  [harness]  @ 119-137
  @case 'trackerMode off: user-authored PCs are not touched'  [harness]  @ 143-152
  @case 'external note enters trackerMode stamped from the prevailing PC'  [harness]  @ 162-177
  @case 'inheritance freezes at stamp time: editing one sample recolours only itself'  [harness]  @ 181-198
  @case 'seed closure: moving a note relocates its PC and leaves neighbours alone'  [harness]  @ 204-222
  @case 'lane-2 note alone (no simultaneous lane-1) emits its own PC'  [harness]  @ 228-248
  @case 'simultaneous lane-1 and lane-2: leftmost wins, loser is shadowed'  [harness]  @ 252-268
  @case 'splitting realised ppqs (delay) un-collides chord into two PCs'  [harness]  @ 272-292
  @case 'deleting the shadower un-shadows the survivor and PC val flips'  [harness]  @ 296-322
  @case 'a PA mid-note synthesises no PC of its own'  [harness]  @ 330-344
  @case 'a lane-1 PA does not outrank a lane-2 note at the same ppq'  [harness]  @ 350-373

# Uses (outbound edges)
  @use call mm:notes  @ 22
  @use call tm:getChannel  @ 28,315,366
  @use call fm:dump  @ 48,67,88,108,135,136,151,171,173,196,220,245,263,286,310,343,364
